public:
    std::vector<int> sortArray(std::vector<int>& nums) {
        for (int i = 0; i < nums.size(); i++) {
            int minIndex = i;
            for (int j = i + 1; j < nums.size(); j++) {
                if (nums[minIndex] > nums[j]) {
                    minIndex = j;
                }
            }

            if (minIndex != i) {
                std::swap(nums[i], nums[minIndex]);
            }
        }

        return nums;
    }
};

